import React, {useEffect} from 'react';
import s from './UploadPreview.module.scss';

function UploadPreview(props) {
    var reader = new FileReader();

    const imagePreview = (file) => (
        <div className={s.item__image}>
            <img src={FileReader.readAsDataURL(file)} alt="Dodane zdjęcie"/>
        </div>
    );

    const previews = props.files.map((file, key) => (
        <div className={s.item}>
            {file.type.indexOf("image/") !== -1 ? imagePreview(file) : null}
        </div>
    ));

    useEffect(() => () => {
        // Make sure to revoke the data uris to avoid memory leaks
        props.files.forEach(file => URL.revokeObjectURL(file.preview));
    }, [props.files]);

    return (
        <div>   
            {previews}
        </div>
    )
}

export default UploadPreview;
